1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  Sword: 1000,
14	  Amulet: 600,
15	  Staff: 800,
16	  Potion: 400,
17	  Rune: 250,
18	  Moonstone: 250,
19	};
20	
21	const FIRST_INSURANCE_PERCENT = 110;
22	const PROCESSING_FEE = 5;
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const CAP_MULTIPLIER = 2;
25	
26	type Item = { type: string; cursed?: boolean; enchantment?: number };
27	type Customer = { name: string; years: number; contracts: number };
28	
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
33	const BLOCK_OF_3_BASE_PREMIUM = 60;
34	const BLOCK_OF_3_SIZE = 3;
35	const CURSED_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	
39	const isBlockOf3Components = (type: string, count: number): boolean =>
40	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
41	
42	const baseForGroup = (type: string, count: number): number =>
43	  isBlockOf3Components(type, count)
44	    ? BLOCK_OF_3_BASE_PREMIUM
45	    : BASE_PREMIUMS[type] * count;
46	
47	const countItemsByType = (items: Item[]): Record<string, number> =>
48	  items.reduce<Record<string, number>>((counts, item) => {
49	    counts[item.type] = (counts[item.type] ?? 0) + 1;
50	    return counts;
51	  }, {});
52	
53	const baseTotalFor = (items: Item[]): number =>
54	  Object.entries(countItemsByType(items))
55	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
56	
57	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
58	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
59	
60	const cursedSurchargeFor = (item: Item): number =>
61	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
62	
63	const highEnchantmentSurchargeFor = (item: Item): number =>
64	  surchargeOnBase(item, (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
65	
66	const itemSurchargesFor = (items: Item[]): number =>
67	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
68	
69	const loyaltyDiscountFor = (customer: Customer, baseTotal: number): number =>
70	  customer.years >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
71	
72	const applyFirstInsurance = (baseTotal: number): number =>
73	  (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
74	
75	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
76	
77	const followUpDiscountFor = (isFollowUp: boolean, baseTotal: number): number =>
78	  isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
79	
80	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
81	  const baseTotal = baseTotalFor(items);
82	  const policyBase = applyFirstInsurance(baseTotal);
83	  const itemSurcharges = itemSurchargesFor(items);
84	  const loyaltyDiscount = loyaltyDiscountFor(customer, baseTotal);
85	  const followUpDiscount = followUpDiscountFor(isFollowUp, baseTotal);
86	  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
87	};
88	
89	type Policy = { items: Item[]; cap: number; remainingCap: number };
90	type Damage = { itemType: string; amount: number };
91	type ClaimStep = { type: "claim"; policy: number; incident: { damages: Damage[] } };
92	type QuoteStep = { type: "quote"; items: Item[] };
93	type Step = QuoteStep | ClaimStep;
94	type Scenario = { customer: Customer; steps: Step[] };
95	type ClaimResult = { payout: number; remainingCap: number };
96	type QuoteResult = { premium: number };
97	
98	const insuranceSumFor = (items: Item[]): number =>
99	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
100	
101	const payoutForDamage = (damage: Damage): number =>
102	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
103	
104	const totalPayoutFor = (damages: Damage[]): number =>
105	  Math.floor(damages.reduce((total, damage) => total + payoutForDamage(damage), 0));
106	
107	const clampToCap = (amount: number, remainingCap: number): number =>
108	  Math.min(amount, remainingCap);
109	
110	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
111	  const policy = policies[step.policy];
112	  const payout = clampToCap(totalPayoutFor(step.incident.damages), policy.remainingCap);
113	  policy.remainingCap -= payout;
114	  return { payout, remainingCap: policy.remainingCap };
115	};
116	
117	const newPolicyFor = (items: Item[]): Policy => {
118	  const cap = CAP_MULTIPLIER * insuranceSumFor(items);
119	  return { items, cap, remainingCap: cap };
120	};
121	
122	const processQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean, policies: Policy[]): QuoteResult => {
123	  policies.push(newPolicyFor(step.items));
124	  return { premium: quotePremium(step.items, customer, isFollowUp) };
125	};
126	
127	export function processScenario(scenario: any): unknown {
128	  const policies: Policy[] = [];
129	  const results = (scenario.steps as Step[]).map((step, index) =>
130	    step.type === "claim"
131	      ? processClaim(step, policies)
132	      : processQuote(step, scenario.customer, index > 0, policies),
133	  );
134	  return { results };
135	}
